    53→export type DeviceCategory = 'light' | 'dimmer' | 'thermostat' | 'sensor' | 'safety' | 'energy' | 'shutter' | 'other';
    54→
    55→export function categorizeDevice(type: string): DeviceCategory {
    56→  if (type.includes('dimmer') || type.includes('colorController')) return 'dimmer';
    57→  if (type.includes('Switch') || type.includes('powerSwitch')) return 'light';
    58→  if (type.includes('hvacSystem')) return 'thermostat';
    59→  if (type.includes('smokeDetector') || type.includes('coDetector') || type.includes('floodSensor')) return 'safety';
    60→  if (type.includes('electricMeter')) return 'energy';
    61→  if (type.includes('Sensor') || type.includes('Detector')) return 'sensor';
    62→  if (type.includes('shutter') || type.includes('cover')) return 'shutter';
    63→  return 'other';
    64→}
