     1→import { FibaroDevice, FibaroRoom, FibaroScene, FibaroWeather } from '../../shared/types.ts';
     2→
     3→const BASE = '/api/fibaro';
     4→const TOKEN = import.meta.env.VITE_API_TOKEN as string;
     5→
     6→async function fetchJSON<T>(url: string): Promise<T> {
     7→  const res = await fetch(url, { headers: { Authorization: `Bearer ${TOKEN}` } });
     8→  if (!res.ok) throw new Error(`HTTP ${res.status}: ${res.statusText}`);
     9→  return res.json() as Promise<T>;
    10→}
    11→
    12→export const api = {
    13→  getRooms: () => fetchJSON<FibaroRoom[]>(`${BASE}/rooms`),
    14→  getDevices: () => fetchJSON<FibaroDevice[]>(`${BASE}/devices`),
    15→  getDevice: (id: number) => fetchJSON<FibaroDevice>(`${BASE}/devices/${id}`),
    16→  getScenes: () => fetchJSON<FibaroScene[]>(`${BASE}/scenes`),
    17→  getWeather: () => fetchJSON<FibaroWeather>(`${BASE}/weather`),
    18→
    19→  deviceAction: async (id: number, action: string, args?: unknown) => {
    20→    const res = await fetch(`${BASE}/devices/${id}/action/${action}`, {
    21→      method: 'POST',
    22→      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${TOKEN}` },
    23→      body: JSON.stringify(args ?? {}),
    24→    });
    25→    if (!res.ok) throw new Error(`HTTP ${res.status}: ${res.statusText}`);
    26→    return res.json();
    27→  },
    28→
    29→  executeScene: async (id: number) => {
    30→    const res = await fetch(`${BASE}/scenes/${id}/execute`, {
    31→      method: 'POST',
    32→      headers: { Authorization: `Bearer ${TOKEN}` },
    33→    });
    34→    if (!res.ok) throw new Error(`HTTP ${res.status}: ${res.statusText}`);
    35→    return res.json();
    36→  },
    37→};
