     1→import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
     2→import { api } from '../services/api.ts';
     3→
     4→export function useRooms() {
     5→  return useQuery({ queryKey: ['rooms'], queryFn: api.getRooms });
     6→}
     7→
     8→export function useDevices() {
     9→  return useQuery({ queryKey: ['devices'], queryFn: api.getDevices, refetchInterval: 30000 });
    10→}
    11→
    12→export function useScenes() {
    13→  return useQuery({ queryKey: ['scenes'], queryFn: api.getScenes, refetchInterval: 60000 });
    14→}
    15→
    16→export function useWeather() {
    17→  return useQuery({ queryKey: ['weather'], queryFn: api.getWeather, refetchInterval: 60000 });
    18→}
    19→
    20→export function useDeviceAction() {
    21→  const queryClient = useQueryClient();
    22→  return useMutation({
    23→    mutationFn: ({ id, action, args }: { id: number; action: string; args?: unknown }) =>
    24→      api.deviceAction(id, action, args),
    25→    onSuccess: () => {
    26→      void queryClient.invalidateQueries({ queryKey: ['devices'] });
    27→    },
    28→  });
    29→}
    30→
    31→export function useSceneExecute() {
    32→  const queryClient = useQueryClient();
    33→  return useMutation({
    34→    mutationFn: (id: number) => api.executeScene(id),
    35→    onSuccess: () => {
    36→      void queryClient.invalidateQueries({ queryKey: ['scenes'] });
    37→    },
    38→  });
    39→}
