    66→                  </div>
    67→                  <div className="h-1.5 bg-gray-700 rounded-full overflow-hidden">
    68→                    <div
    69→                      className="h-full bg-green-500 rounded-full transition-all"
    70→                      style={{ width: `${pct}%` }}
    71→                    />
    72→                  </div>
    73→                </div>
    74→              );
    75→            })}
    76→          </div>
    77→        </div>
