                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {powerDevices.length === 0 && energyMeters.length === 0 && (
        <div className="text-center py-12 text-gray-500">No energy data available</div>
      )}
    </div>
  );
}
